qry:select.qry:xquery:
					for $r in sql('
			SELECT PER02_PERSONAL_EMP.oi_personal_emp, TTA04_PERSONAL.d_nro_tarjeta,
			PER02_PERSONAL_EMP.e_numero_legajo, 
			PER02_PERSONAL_EMP.oi_empresa, PER02_PERSONAL_EMP.oi_personal, PER11_TIPOS_PERS.d_tipo_personal,						
			PER02_PERSONAL_EMP.f_ingreso, ORG03_EMPRESAS.c_empresa, PER01_PERSONAL.d_apellido
			FROM PER02_PERSONAL_EMP, TTA04_PERSONAL, PER11_TIPOS_PERS, ORG03_EMPRESAS, PER01_PERSONAL
			JOIN PER02_PERSONAL_EMP.oi_personal_emp LEFT OUTER TTA04_PERSONAL.oi_personal_emp,
			PER02_PERSONAL_EMP.oi_tipo_personal INNER PER11_TIPOS_PERS.oi_tipo_personal,
			PER02_PERSONAL_EMP.oi_empresa INNER ORG03_EMPRESAS.oi_empresa,
			PER02_PERSONAL_EMP.oi_personal INNER PER01_PERSONAL.oi_personal
			WHERE 1=1 
			{%? (#SOURCE:@EMPRESA!='')	{% AND PER02_PERSONAL_EMP.oi_empresa = {#SOURCE:@EMPRESA} %} {% %} %}
			{%? (#SOURCE:@TIPO_PER!='')	{% AND PER02_PERSONAL_EMP.oi_tipo_personal ={#SOURCE:@TIPO_PER} %} {% %} %}						
   		{%? (#SOURCE:@F_HASTA!='') {% AND PER02_PERSONAL_EMP.f_ingreso < {DateTime(#SOURCE:@F_HASTA)} %} {% %} %}
   		{%? (#SOURCE:@F_DESDE!='') {% AND PER02_PERSONAL_EMP.f_ingreso > {DateTime(#SOURCE:@F_DESDE)} %} {% %} %}
   		{%? (#SOURCE:@oi_indic_activo!='') {% AND PER02_PERSONAL_EMP.oi_indic_activo = {#SOURCE:@oi_indic_activo} %} {% %} %}
   		{%? (string(#SOURCE:LEGAJOS/LEGAJO/@id)!='') {% AND PER02_PERSONAL_EMP.oi_personal_emp in ({%=string(#SOURCE:LEGAJOS/LEGAJO/@id) %}) %} {%  %} %}       			
     	ORDER BY 
     	{%? (#SOURCE:@ATRIB_ORDEN1!='') {% {%=#SOURCE:@ATRIB_ORDEN1%} {%=#SOURCE:@ORDEN1 %}, %} {% %} %} 
    	{%? (#SOURCE:@ATRIB_ORDEN2!='') {% {%=#SOURCE:@ATRIB_ORDEN2%} {%=#SOURCE:@ORDEN2 %}, %} {% %} %} 	
	    {%? (#SOURCE:@ATRIB_ORDEN3!='') {% {%=#SOURCE:@ATRIB_ORDEN3%} {%=#SOURCE:@ORDEN3 %}, %} {% %} %}
    	{%? (#SOURCE:@ATRIB_ORDEN4!='') {% {%=#SOURCE:@ATRIB_ORDEN4%} {%=#SOURCE:@ORDEN4 %}, %} {% %} %} 	
    	{%? (#SOURCE:@ATRIB_ORDEN5!='') {% {%=#SOURCE:@ATRIB_ORDEN5%} {%=#SOURCE:@ORDEN5 %}, %} {% %} %} 
    	oi_personal_emp ASC						
			')/ROWS/ROW

		for $r in sql('
		SELECT TTA04_PERSONAL.oi_personal_emp 
		FROM TTA04_PERSONAL
		WHERE 
		{%? (#SOURCE:@e_nro_legajo_reloj !='') 
			{% TTA04_PERSONAL.oi_personal_emp != {#SOURCE:@id} 
				 AND TTA04_PERSONAL.e_nro_legajo_reloj = {#SOURCE:@e_nro_legajo_reloj} %} 
			{% 1 = 2  %}
	  %}										
')/ROWS/ROW

		for $r in sql('
		SELECT TTA04_PERSONAL.oi_personal_emp 
		FROM TTA04_PERSONAL
		WHERE 
		{%? (#SOURCE:@d_nro_tarjeta !='') 
			{% TTA04_PERSONAL.oi_personal_emp != {#SOURCE:@id}
				 AND TTA04_PERSONAL.d_nro_tarjeta = \'{#SOURCE:@d_nro_tarjeta}\' %} 
		  {% 1 = 2  %}
	  %}
')/ROWS/ROW
